diff -u -d -r1.51 ls.c
--- ls.c	29 Dec 2001 00:22:29 -0000	1.51
+++ ls.c	9 Jan 2002 13:34:48 -0000
@@ -135,7 +135,7 @@
 {
 	static char dot[] = ".", *dotav[] = {dot, NULL};
 	struct winsize win;
-	int ch, fts_options, notused;
+	int ch, fts_options, i, len, notused;
 	char *p;
 #ifdef COLORLS
 	char termcapbuf[1024];	/* termcap definition buffer */
@@ -392,6 +392,17 @@
 		printfcn = printlong;
 	else
 		printfcn = printcol;
+
+	/*
+	 * If -d and -F options, strip trailing slashes from arguments
+	 * to avoid duplicated terminating slashes in output.
+	 */
+	if (f_listdir && f_type)
+		for(i=0; i < argc ; i++) {
+			len = strlen(argv[i]);
+			if (argv[i][len - 1] == '/')
+				argv[i][len - 1] = '\0';
+		}

 	if (argc)
 		traverse(argc, argv, fts_options);
